<template>
    <view>
        <u-navbar title="メニュー" :placeholder="true" :autoBack="false" @leftClick="goBack" :safeAreaInsetTop="true">
            <view class="u-nav-slot" slot="right">
                <image src="../../static/icons/addBlue.png" style="width: 60upx;height: 60upx;" @click="add" mode="">
                </image>
            </view>
        </u-navbar>
        <view class="tabs border_top">
            <view class="tab_item" v-for="(item,index) in array" v-text="item.cate"></view>
        </view>
        <view class="content">
            <view class="item" v-for="(item,index) in array">
                <view class="itemTitle border_bottom" v-text="item.cate"></view>
                <view class="itemContent">
                    <view class="ite border_bottom" v-for="(ite,idx) in item.items">
                        <view class="iteTitle" v-text="ite.title"></view>
                        <view class="iteContent">
                            <view class="iteImage">
                                <image :src="ite.image[0]" mode=""></image>
                            </view>
                            <view class="iteInfo">
                                <view class="price" v-text="`¥${ite.price}`"></view>
                                <view class="time" v-text="`所要時間: ${ite.order_time}分`"></view>
                            </view>
                        </view>
                    </view>
                </view>
            </view>
        </view>
    </view>
</template>

<script>
    import {
        menuCateList,
        menuList
    } from '@/api/index.js'
    export default {
        data() {
            return {
                array: []
            };
        },
        created() {
            let that = this
            that.getCate()
        },
        methods: {
            add() {
                uni.navigateTo({
                    url: "../menu/add/add"
                })
            },
            
            goBack(){
              uni.switchTab({
                  url:"../setting/setting"
              })  
            },

            getCate() {
                let that = this
                menuCateList().then((res) => {
                    if (res.code == 200) {
                        menuList().then((result) => {
                            if (res.code == 200) {
                                let array = []
                                for (let i = 0; i < res.data.cates.length; i++) {
                                    let obj = {}
                                    obj.id = res.data.cates[i].id
                                    obj.cate = res.data.cates[i].name
                                    let temp = []
                                    for (let j = 0; j < result.data.menus.length; j++) {
                                        if (result.data.menus[j].cid == res.data.cates[i].id) {
                                            temp.push(result.data.menus[j])
                                        }
                                    }
                                    obj.items = temp
                                    array.push(obj)
                                }
                                that.array = array
                            }
                        })
                    }
                })
            }
        }
    }
</script>

<style lang="scss">
    .itemTitle {
        box-sizing: border-box;
        padding: 36upx 32upx;
        background: #F5F5F7
    }

    .iteContent {
        display: flex;
        align-items: flex-start;

        .iteInfo {
            display: flex;

            .price {
                color: #D93025;
                font-size: 28upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                margin-right: 60upx;
            }

            .time {
                color: #1D1D1F;
                font-size: 28upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
            }
        }

        .iteImage {
            width: 200upx;
            height: 200upx;
            margin-right: 32upx;

            image {
                width: 100%;
                height: 100%;
                border-radius: 12upx;
            }
        }
    }

    .iteTitle {
        font-size: 32upx;
        font-family: Hiragino Sans-W5, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        margin-bottom: 32upx;
    }

    .ite {
        box-sizing: border-box;
        padding: 40upx 32upx;
    }

    .tabs {
        display: flex;
        align-items: center;
        overflow-x: scroll;
        box-sizing: border-box;
        padding: 60upx 32upx;
        box-shadow: 0px 0px 12upx 2upx rgba(0, 0, 0, 0.16);

        .tab_item {
            padding: 20upx;
            background: #FFFFFF;
            border-radius: 10upx;
            border: 2upx solid #86868B;
            font-size: 24upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #86868B;
            flex-shrink: 0;
            margin-right: 40upx;
        }
    }
</style>
